import"./app-yIULqX0W.js";const s={"Food & Beverage":"🍽️",Retail:"🛍️","Health & Wellness":"💊",Technology:"💻",Education:"📚",Finance:"💰","Real Estate":"🏠","Beauty & Salon":"💇",Automotive:"🚗",Entertainment:"🎭","Travel & Tourism":"✈️","Home Services":"🔧",Legal:"⚖️","Sports & Fitness":"🏋️",Fashion:"👗",Other:"📦"};async function o(){const t=document.getElementById("search-cat"),n=document.getElementById("categories-grid");CATEGORIES.forEach(e=>{t.innerHTML+=`<option value="${e}">${e}</option>`,n.innerHTML+=`<div class="cat-card" onclick="browseCategory('${e}')">
      <div class="cat-icon">${s[e]||"📦"}</div>
      <div class="cat-name">${e}</div>
    </div>`});try{const e=await apiFetch("/listings?limit=6");document.getElementById("stat-count").textContent=e.length>=6?"100+":e.length;const i=document.getElementById("listings-grid");e.length?i.innerHTML=e.map(renderCard).join(""):i.innerHTML='<div class="empty-state" style="grid-column:1/-1"><div class="empty-icon">🏪</div><h3>No listings yet</h3><p>Be the first to list your business!</p></div>'}catch{document.getElementById("listings-grid").innerHTML='<div style="grid-column:1/-1;color:var(--text3);text-align:center;padding:40px;">Could not connect to API. Make sure the backend is running.</div>'}}function a(){const t=document.getElementById("search-input").value.trim(),n=document.getElementById("search-cat").value,e=new URLSearchParams;t&&e.set("q",t),n&&e.set("category",n),window.location.href=`/pages/listings.html?${e}`}document.getElementById("search-input").addEventListener("keydown",t=>{t.key==="Enter"&&a()});function c(t){window.location.href=`/pages/listings.html?category=${encodeURIComponent(t)}`}o();window.browseCategory=c;window.init=o;window.doSearch=a;
